<?php
$cmsAdminTitle='Quiz Attempt Reporting';require_once __DIR__.'/../includes/cms-admin-header.php';$pathway=(string)($_GET['pathway']??'All');$sql='SELECT a.*,l.full_name,l.email FROM academy_quiz_attempts a JOIN learners l ON l.id=a.learner_id';$params=[];if(in_array($pathway,['Kids','Business','General'],true)){$sql.=' WHERE a.pathway=?';$params[]=$pathway;}$sql.=' ORDER BY a.created_at DESC';$s=$pdo->prepare($sql);$s->execute($params);$rows=$s->fetchAll();
?>
<div class="admin-top"><div><p class="eyebrow">All scored submissions</p><h1>Quiz Attempts</h1></div><form><select class="form-select" name="pathway" onchange="this.form.submit()"><option>All</option><?php foreach(['Kids','Business','General'] as $v):?><option <?=$pathway===$v?'selected':''?>><?=$v?></option><?php endforeach?></select></form></div><div class="glass-card table-responsive"><table class="table table-dark"><tr><th>Learner</th><th>Pathway</th><th>Quiz / Lesson</th><th>Score</th><th>Result</th><th>Date</th></tr><?php foreach($rows as $row):?><tr><td><strong><?=e($row['full_name'])?></strong><small class="d-block text-secondary"><?=e($row['email'])?></small></td><td><?=e($row['pathway'])?></td><td>Quiz #<?=(int)$row['quiz_id']?> / Lesson #<?=(int)$row['lesson_id']?></td><td><?=(int)$row['score']?>%</td><td><span class="tag"><?=$row['passed']?'Passed':'Retry'?></span></td><td><?=e(date('M j, Y H:i',strtotime($row['created_at'])))?></td></tr><?php endforeach?></table></div>
<?php require_once __DIR__.'/../includes/cms-admin-footer.php';?>